using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using HtmlSanitizer;

public class ReviewController : Controller
{
    private readonly IReviewRepository _reviewRepository;
    private readonly HtmlSanitizer _sanitizer;

    public ReviewController(IReviewRepository reviewRepository)
    {
        _reviewRepository = reviewRepository;
        _sanitizer = new HtmlSanitizer();
        _sanitizer.AllowedTags.Add("b");
        _sanitizer.AllowedTags.Add("i");
        _sanitizer.AllowedTags.Add("u");
        _sanitizer.AllowedAttributes.Add("style");
    }

    public ActionResult Index(int productId)
    {
        var reviews = _reviewRepository.GetReviewsByProductId(productId);
        var viewModel = reviews.Select(r => new ReviewViewModel
        {
            Id = r.Id,
            Comment = _sanitizer.Sanitize(r.Comment),
            Rating = r.Rating,
            UserName = r.UserName,
            CreatedDate = r.CreatedDate
        }).ToList();

        return View(viewModel);
    }
}

public class ReviewViewModel
{
    public int Id { get; set; }
    public string Comment { get; set; }
    public int Rating { get; set; }
    public string UserName { get; set; }
    public DateTime CreatedDate { get; set; }
}

public interface IReviewRepository
{
    IEnumerable<Review> GetReviewsByProductId(int productId);
}

public class Review
{
    public int Id { get; set; }
    public string Comment { get; set; }
    public int Rating { get; set; }
    public string UserName { get; set; }
    public DateTime CreatedDate { get; set; }
    public int ProductId { get; set; }
}